 4→export interface CommandRegistration {
 5→  id: string;
 6→  name: string;
 7→  subtitle?: string;
 8→  icon: ReactNode;
 9→  keywords?: string[];
10→  aliases?: string[];
11→  section: string;
12→  accessories?: ListItemAccessoryData[];
13→  detail?: ListItemDetailData;
14→  component?: ComponentType;
15→  fullView?: boolean;
